dataset.prompt_raw_json:
{
  "parts": [
    {
      "text": "Hello, what can you help me with?"
    }
  ],
  "role": "user"
}

dataset.response_raw_json:
{
  "parts": [
    {
      "text": "Hello! I'm here to help you view documents.\n\nYou can ask me to display a PDF or DOCX document hosted on Google Cloud Storage. Just provide the full GCS URI.\n\nFor example, you could say: \"show gs://hcls-ge-documents/roi_2025_health.pdf\" or \"display gs://ge-demo-docs/atest.docx\"."
    }
  ],
  "role": "model"
}

