1. surfaceUpdate(surfaceId='main_app', components=[{
     'id': 'root',
     'component': {
       'Column': {
         'children': {
           'explicitList': ['iframe']
         }
       }
     }
   }, {
     'id': 'iframe',
     'component': {
       'WebFrameUrl': {
         'url': {
           'literalString': 'http://localhost:8000/docx?url=gs://ge-demo-docs/atest.docx'
         },
         'height': 800
       }
     }
   }])
2. beginRendering(surfaceId='main_app', root='root')
